with open(FILE, 'r', encoding='utf-8') as f:
    data = json.load(f)

data.extend(new_categories)

with open(FILE, 'w', encoding='utf-8') as f:
    json.dump(data, f, ensure_ascii=False, indent=2)

print(f"Added {len(new_categories)} categories ({sum(len(c['items']) for c in new_categories)} items)")
print(f"Total: {len(data)} categories, {sum(len(c.get('items',[])) for c in data)} items")

# Check for duplicate IDs
all_ids = []
for c in data:
    for item in c.get('items', []):
        all_ids.append(item['id'])
dupes = [x for x in set(all_ids) if all_ids.count(x) > 1]
if dupes:
    print(f"WARNING: Duplicate item IDs: {dupes}")
else:
    print("No duplicate item IDs found.")
